use serde::Serialize;

#[derive(Serialize)]
struct User {
    name: String,
}

fn get_config() -> String {
    let user = User { name: "Alice".to_string() };
    // This will produce an empty string if serialization fails, hiding the error.
    serde_json::to_string(&user).unwrap_or_default()
}

fn read_file() -> Option<String> {
    // This converts any file read error (permissions, etc.) into None, same as not found.
    std::fs::read_to_string("config.txt").ok()
}

rule.negative_fixture:
use std::io::ErrorKind;

fn read_config() -> Result<Option<String>, std::io::Error> {
    match std::fs::read_to_string("config.json") {
        Ok(s) => Ok(Some(s)),
        Err(e) if e.kind() == ErrorKind::NotFound => Ok(None), // Explicitly handle NotFound
        Err(e) => Err(e), // Propagate other errors
    }
}

