rule.negative_fixture:
use std::fs;
use std::path::Path;

fn setup_dir() -> std::io::Result<()> {
    let path = Path::new("/tmp/my_app");
    // CORRECT: The result is propagated.
    fs::create_dir_all(path)?;
    Ok(())
}

fn setup_dir_explicit_ignore() {
    let path = Path::new("/tmp/my_app");
    // OK: The result is explicitly ignored, showing intent.
    let _ = fs::create_dir_all(path);
}

rule.positive_fixture:
use std::time::{SystemTime, UNIX_EPOCH};

fn get_offset() -> u64 {
    let now = SystemTime::now();
    // This will panic if the system clock is set to a time before the Unix epoch.
    now.duration_since(UNIX_EPOCH).unwrap().as_secs()
}

rule.negative_fixture:
use std::time::{SystemTime, UNIX_EPOCH, SystemTimeError};

fn get_offset() -> Result<u64, SystemTimeError> {
    let now = SystemTime::now();
    let duration = now.duration_since(UNIX_EPOCH)?;
    Ok(duration.as_secs())
}
